const cfg = $('⚙️ Set Config').first().json;
const sd = $getWorkflowStaticData('global');
// Clear any leftover state from a previous (possibly interrupted) run
sd.candidates = [];
sd.unmatchedImages = [];
sd.skippedNoUrlCount = 0;
sd.skippedAlreadyFailedCount = 0;
sd.skippedCategories = [];

const folders = $input.all().map(i => i.json);
const categories = (cfg.categories || '').split(',').map(s => s.trim()).filter(Boolean);

function norm(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[\s_-]+/g, '')
    .trim();
}

const out = [];
for (const category of categories) {
  const target = norm(category);
  const match = folders.find(f => norm(f.name) === target);
  if (!match) {
    sd.skippedCategories.push(category);
    continue;
  }
  out.push({ json: { category, folderId: match.id } });
}
return out;

return $input.all()
  .filter(({ json }) => /\.(png|jpe?g|webp)$/i.test(json.name || ''))
  .map(({ json }) => ({ json: { id: json.id, name: json.name, mimeType: json.mimeType || '' } }));

const cfg = $('⚙️ Set Config').first().json;
const category = $('🔁 Iterate Category Folders').item.json.category;

// Some category tabs have a plain single-row header (row 1 = real headers,
// data from row 2). Others have a 2-row header (row 1 = assorted notes/labels,
// row 2 = the real headers, data from row 3) -- the same layout already known
// from the Wall-Coverings tab. Rather than hardcode which tabs use which
// layout (fragile -- a single miscategorized tab silently returns zero
// matches), detect it directly from the data: if 'Product No.' isn't already
// a usable key, find the row whose VALUES contain 'Product No.' literally --
// that's the real header row -- and remap every row after it accordingly.
function remapProductRows(rows) {
  const alreadyGood = rows.some(r => Object.prototype.hasOwnProperty.call(r, 'Product No.') && String(r['Product No.'] || '').trim());
  if (alreadyGood) return rows;

  const headerRowIndex = rows.findIndex(r => Object.values(r).some(v => String(v ?? '').trim() === 'Product No.'));
  if (headerRowIndex === -1) return []; // headers not found in any layout -- nothing usable for this tab

  const headerRow = rows[headerRowIndex];
  const keyToRealHeader = {};
  for (const [key, value] of Object.entries(headerRow)) {
    const label = String(value ?? '').trim();
    if (label) keyToRealHeader[key] = label;
  }

  return rows.slice(headerRowIndex + 1).map(r => {
    const remapped = {};
    for (const [key, value] of Object.entries(r)) {
      remapped[keyToRealHeader[key] || key] = value;
    }
    return remapped;
  });
}

const productRows = remapProductRows($input.all().map(i => i.json));
const images = $('🖼️ Filter Image Files').all().map(i => i.json);

const sd = $getWorkflowStaticData('global');

const pinnedFileIds = new Set(
  $('📌 Get Existing Pin Rows').all()
    .map(i => String(i.json['Image File ID'] || '').trim())
    .filter(Boolean)
);

const failedAttempts = new Map();
for (const row of $('🚫 Get Failed Images').all()) {
  const fid = String(row.json['Image File ID'] || '').trim();
  const count = parseInt(row.json['Attempt Count'], 10) || 0;
  if (fid) failedAttempts.set(fid, count);
}

// Build product lookup: every Product No. in this tab, whether or not it has a Shopify URL yet
const productMap = new Map();       // canonical Product No. -> {shopifyUrl, material, keyword}
const productNoByUpper = new Map(); // UPPERCASE(Product No.) -> canonical Product No. (for exact lookup)
for (const row of productRows) {
  const no = String(row['Product No.'] || '').trim();
  if (!no) continue;
  productMap.set(no, {
    shopifyUrl: String(row['Shopify_Product_URL'] || '').trim(),
    material:   row['Material'] || '',
    keyword:    row['Keywords (Luna)'] || '',
  });
  productNoByUpper.set(no.toUpperCase(), no);
}

// The Product No. is the leading alphanumeric token of the filename
// (e.g. "LSBLD178- (1)_2x3.jpg" -> "LSBLD178"). Matched by EXACT equality
// against the sheet's Product No. values -- no substring/"contains" logic,
// so "LSBLD178" can never accidentally match "LSBLD17" or vice versa.
function matchProductNo(fileName) {
  const m = String(fileName || '').match(/^[A-Za-z0-9]+/);
  if (!m) return null;
  return productNoByUpper.get(m[0].toUpperCase()) || null;
}

const groups = {};
let skippedNoUrlCount = 0;
let skippedAlreadyFailedCount = 0;
const unmatchedImages = [];

for (const img of images) {
  const productNo = matchProductNo(img.name || '');
  if (!productNo) { unmatchedImages.push({ category, name: img.name }); continue; }

  const info = productMap.get(productNo);
  if (!info.shopifyUrl) { skippedNoUrlCount++; continue; }

  if (pinnedFileIds.has(img.id)) continue; // already pinned -- the actual dedup guarantee

  const attempts = failedAttempts.get(img.id) || 0;
  if (attempts >= (cfg.maxUploadAttempts || 3)) { skippedAlreadyFailedCount++; continue; }

  if (!groups[productNo]) {
    groups[productNo] = {
      productNo, category,
      shopifyUrl: info.shopifyUrl,
      material: info.material,
      keyword: info.keyword,
      images: [],
    };
  }
  groups[productNo].images.push(img);
}

function naturalCompare(a, b) {
  return a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' });
}

const perProductCap = cfg.perProductDailyCap || 10;
const entries = Object.values(groups).map(g => {
  g.images.sort((a, b) => naturalCompare(a.name, b.name));
  g.images = g.images.slice(0, perProductCap);
  return g;
}).filter(g => g.images.length > 0);

sd.candidates = (sd.candidates || []).concat(entries);
sd.unmatchedImages = (sd.unmatchedImages || []).concat(unmatchedImages);
sd.skippedNoUrlCount = (sd.skippedNoUrlCount || 0) + skippedNoUrlCount;
sd.skippedAlreadyFailedCount = (sd.skippedAlreadyFailedCount || 0) + skippedAlreadyFailedCount;

return [{ json: { category, matchedProducts: entries.length, imagesQueued: entries.reduce((n, e) => n + e.images.length, 0) } }];

const cfg = $('⚙️ Set Config').first().json;
const sd = $getWorkflowStaticData('global');
const candidates = sd.candidates || [];

const pinnedRows = $('📌 Get Existing Pin Rows').all().map(i => i.json);

// Fairness ordering: products with fewest ALREADY-PUBLISHED-OR-QUEUED images
// (from actual Pinterest Pins history) go first, so no product gets starved
// while others pile up.
function pinnedCountFor(productNo) {
  return pinnedRows.filter(r => String(r['Product No.'] || '').trim() === productNo).length;
}

const sorted = [...candidates].sort((a, b) => {
  const diff = pinnedCountFor(a.productNo) - pinnedCountFor(b.productNo);
  if (diff !== 0) return diff;
  return a.productNo.localeCompare(b.productNo);
});

// Round-robin flatten: one image at a time from each product in priority
// order, cycling until EVERY eligible image is included (not capped to a
// subset) -- a product with 2 images now always gets 2 rows, just possibly
// scheduled on different days.
const pointers = sorted.map(() => 0);
const flatList = [];
let progressed = true;
while (progressed) {
  progressed = false;
  for (let i = 0; i < sorted.length; i++) {
    const group = sorted[i];
    if (pointers[i] >= group.images.length) continue;
    const img = group.images[pointers[i]];
    pointers[i]++;
    progressed = true;
    flatList.push({
      productNo: group.productNo, category: group.category,
      shopifyUrl: group.shopifyUrl, material: group.material, keyword: group.keyword,
      fileId: img.id, fileName: img.name, mimeType: img.mimeType,
    });
  }
}

// Clear accumulated state now that it's been consumed
sd.candidates = [];

// -- Scheduling: pinsPerDay new pins per day, each scheduleHourSpacing hours
// apart, continuing from whatever slot the last already-scheduled
// product-photo pin used (so re-running this daily extends the schedule
// further out instead of double-booking the same slots).
const pinsPerDay = cfg.pinsPerDay || 10;
const hourSpacing = cfg.scheduleHourSpacing || 2;
const dayStartHour = cfg.scheduleDayStartHour || 4;

const existingScheduled = pinnedRows
  .filter(r => String(r['Source'] || '').trim() === 'product-photo')
  .map(r => String(r['Scheduled Date'] || '').trim())
  .filter(Boolean)
  .map(s => DateTime.fromFormat(s, 'yyyy-LL-dd HH:mm'))
  .filter(d => d.isValid);

const tomorrowStart = $now.plus({ days: 1 }).set({ hour: dayStartHour, minute: 0, second: 0, millisecond: 0 });

let cursor = existingScheduled.length ? DateTime.max(...existingScheduled).plus({ hours: hourSpacing }) : tomorrowStart;
if (cursor < tomorrowStart) cursor = tomorrowStart; // never schedule earlier than tomorrow

// If the last existing slot wasn't day-aligned to pinsPerDay (e.g. config
// changed), just keep incrementing by hourSpacing and roll to the next
// day's start hour once a day's quota is filled from THIS point forward.
const finalList = flatList.map((item, idx) => {
  if (idx > 0) {
    const daySlot = idx % pinsPerDay;
    cursor = daySlot === 0
      ? cursor.plus({ days: 1 }).set({ hour: dayStartHour, minute: 0, second: 0, millisecond: 0 })
      : cursor.plus({ hours: hourSpacing });
  }
  return { json: { ...item, scheduledDate: cursor.toFormat('yyyy-LL-dd HH:mm') } };
});

console.log(JSON.stringify({
  totalProducts: sorted.length,
  totalImagesScheduled: finalList.length,
  daysSpanned: Math.ceil(finalList.length / pinsPerDay),
  firstScheduledDate: finalList[0] ? finalList[0].json.scheduledDate : null,
  lastScheduledDate: finalList.length ? finalList[finalList.length - 1].json.scheduledDate : null,
  unmatchedImages: sd.unmatchedImages,
  skippedNoUrlCount: sd.skippedNoUrlCount,
  skippedAlreadyFailedCount: sd.skippedAlreadyFailedCount,
  skippedCategories: sd.skippedCategories,
}));

return finalList.length ? finalList : [{ json: { _noImagesToProcess: true } }];

const ctx = $('🔁 Iterate Final Images').item.json;
const staged = $('🎯 Staged Create').item.json;
const uploadResp = $('☁️ Upload to Storage').item.json;
const fileCreateResp = $('📎 File Create').item.json;
const cdnResp = $json; // Get CDN URL output

function errText(r) {
  if (!r) return '';
  if (r.error) return typeof r.error === 'string' ? r.error : (r.error.message || JSON.stringify(r.error));
  const ue = r.data && (r.data.stagedUploadsCreate || r.data.fileCreate);
  if (ue && ue.userErrors && ue.userErrors.length) return ue.userErrors.map(e => e.message).join('; ');
  return '';
}

let error = errText(staged) || errText(uploadResp) || errText(fileCreateResp) || errText(cdnResp);

const fileId = fileCreateResp?.data?.fileCreate?.files?.[0]?.id;
let cdnUrl = '';
if (!error && fileId) {
  const nodesArr = cdnResp?.data?.nodes || [];
  const node = nodesArr.find(n => n && n.id === fileId);
  cdnUrl = node?.url || node?.image?.url || '';
  if (!cdnUrl) error = 'No CDN URL returned';
}

const success = !error && !!cdnUrl;

// Resolve candidate boards for this pin's category from the Tailwind Boards tab.
// A board's Category cell can list more than one category (e.g. "Bathtub | Fireplace"),
// so split on "|" (and "," as a safety net) rather than requiring an exact single match.
function normCategory(s) { return String(s || '').toLowerCase().replace(/[\s_-]+/g, '').trim(); }
const boardRows = $('🗂️ Get Tailwind Boards').all().map(i => i.json);
const targetCategory = normCategory(ctx.category);
const candidateBoards = boardRows
  .filter(row => String(row['Category'] || '').split(/[|,]/).map(normCategory).includes(targetCategory))
  .map(row => ({ name: String(row['Pinterest Board'] || '').trim(), id: String(row['Tailwind Board ID'] || '').trim() }))
  .filter(b => b.name && b.id);

const needsBoardChoice = success && candidateBoards.length > 1;
const boardInstruction = needsBoardChoice
  ? ('\n\nAlso choose the single best-fit Pinterest board for this image from this exact list (return its exact name as "board" in the JSON): '
    + candidateBoards.map(b => b.name).join(' | '))
  : '';
const jsonKeys = needsBoardChoice ? 'title, description, alt, board' : 'title, description, alt';

const promptText = success
  ? ('You are a Pinterest SEO copywriter for a luxury natural stone product. Look at the image and return ONLY a JSON object with keys: ' + jsonKeys + '. '
    + 'title: <=100 chars, keyword-rich, compelling. description: <=480 chars, keyword-rich, natural, with a soft call to action. alt: <=120 chars, plainly describe the image. '
    + 'Do not include any text or markdown outside the JSON.\n\n'
    + 'Category: ' + ctx.category + '\nMaterial: ' + (ctx.material || 'natural stone') + '\nKeyword: ' + (ctx.keyword || '')
    + '\nThis pin links to the product page: ' + ctx.shopifyUrl
    + boardInstruction)
  : '';

return [{
  json: {
    ...ctx,
    success,
    cdnUrl,
    errorMessage: error,
    promptText,
    candidateBoards,
  },
}];

const ctx = $('🧩 Check Upload Result').item.json;
const resp = $json;
let content = resp.content || resp.text || (resp.message && resp.message.content) || '';
if (!content && resp.choices && resp.choices[0] && resp.choices[0].message) content = resp.choices[0].message.content || '';
content = String(content).replace(/```json/gi, '').replace(/```/g, '').trim();
let ai = {};
try { ai = JSON.parse(content); } catch (e) { ai = {}; }

function preview(u) { return u ? '=IMAGE("' + u + '", 4, 90, 90)' : ''; }

// Resolve the board: single candidate -> use it directly; multiple candidates ->
// use the AI's pick (falling back to the first one if the AI's answer doesn't match
// any candidate name exactly); zero candidates -> leave blank for manual assignment.
const candidateBoards = ctx.candidateBoards || [];
let board = '', boardId = '';
if (candidateBoards.length === 1) {
  board = candidateBoards[0].name;
  boardId = candidateBoards[0].id;
} else if (candidateBoards.length > 1) {
  const aiChoice = String(ai.board || '').trim().toLowerCase();
  const matched = candidateBoards.find(b => b.name.trim().toLowerCase() === aiChoice);
  const chosen = matched || candidateBoards[0];
  board = chosen.name;
  boardId = chosen.id;
}

return [{
  json: {
    'Pin ID': ctx.productNo + '-' + ctx.fileId,
    'Product No.': ctx.productNo,
    'Image File ID': ctx.fileId,
    'Source': 'product-photo',
    'Blog No.': '',
    'Blog Title': '',
    'Pin Type': 'single',
    'Preview 1': preview(ctx.cdnUrl),
    'Image 1 URL': ctx.cdnUrl,
    'Pin Title': ai.title || '',
    'Pin Description': ai.description || '',
    'Alt Text': ai.alt || '',
    'Blog Link': ctx.shopifyUrl,
    // Auto-filled from the Tailwind Boards tab by category (AI-picked when a category
    // has more than one candidate board); left blank only if this category has none yet --
    // WF2 will correctly hold those rows as not-ready ('Board not found') until a board
    // is added for that category, even though Approval is auto-set below.
    'Board': board,
    'Board ID': boardId,
    'Scheduled Date': ctx.scheduledDate || '',
    'Approval': 'Approved',
    'Status': 'Review',
    'Pin URL': '',
    'Error': '',
    'Created Time': $now.toISO(),
    'Pinned Time': '',
  },
}];

const ctx = $json; // Check Upload Result output, false branch
const existing = $('🚫 Get Failed Images').all().map(i => i.json);
const prior = existing.find(r => String(r['Image File ID'] || '').trim() === ctx.fileId);
const attemptCount = (prior ? (parseInt(prior['Attempt Count'], 10) || 0) : 0) + 1;

return [{
  json: {
    'Image File ID': ctx.fileId,
    'Product No.': ctx.productNo,
    'Last Error': ctx.errorMessage || 'Unknown error',
    'Attempt Count': attemptCount,
    'Last Attempt': $now.toISO(),
  },
}];

// Runs once per loop iteration (Iterate Final Images has batchSize 1).
// After the Merge (append mode) the paired-item lineage is broken, so read
// each source node with .first() instead of .item, and re-anchor pairedItem
// to input item 0 (the Staged Create branch of the merge) so downstream nodes
// that reference $('🎯 Staged Create').item / $('🔁 Iterate Final Images').item
// can still resolve.
const staged = $('🎯 Staged Create').first().json;
const downloadItem = $('⬇️ Download from Drive').first();
return [{ json: staged, binary: downloadItem.binary, pairedItem: { item: 0 } }];
